package com.oyuki.report.controller; import com.oyuki.complaint.repository.ComplaintRepository; import com.oyuki.exportrequest.repository.ExportRequestRepository; import com.oyuki.order.repository.OrderRepository; import com.oyuki.product.repository.ProductRepository; import com.oyuki.user.repository.UserRepository; import com.oyuki.wallet.repository.WithdrawalRequestRepository; import org.springframework.web.bind.annotation.*; import java.util.*; @RestController @RequestMapping("/api/admin/reports") public class AdminReportController { private final UserRepository users;private final ProductRepository products;private final OrderRepository orders;private final ComplaintRepository complaints;private final ExportRequestRepository exports;private final WithdrawalRequestRepository withdrawals;public AdminReportController(UserRepository u,ProductRepository p,OrderRepository o,ComplaintRepository c,ExportRequestRepository e,WithdrawalRequestRepository w){users=u;products=p;orders=o;complaints=c;exports=e;withdrawals=w;} @GetMapping("/summary") public Map<String,Object> summary(){Map<String,Object>m=new LinkedHashMap<>();m.put("users",users.count());m.put("products",products.count());m.put("orders",orders.count());m.put("complaints",complaints.count());m.put("exportRequests",exports.count());m.put("withdrawalRequests",withdrawals.count());return m;} }